using System; using System.Threading.Tasks; using Npgsql; class Program { static async Task Main() { var conn = new NpgsqlConnection("Host=localhost;Port=5432;Database=Frametric;Username=postgres;Password=1234"); await conn.OpenAsync(); await using var cmd = new NpgsqlCommand("SELECT ""EnrichmentStatus"", COUNT(*) FROM ""Movies"" GROUP BY ""EnrichmentStatus"";", conn); await using var reader = await cmd.ExecuteReaderAsync(); while(await reader.ReadAsync()) Console.WriteLine($"Status {reader.GetInt32(0)}: {reader.GetInt64(1)} movies"); } }
